from collections import Counter

def count_words(filename):
    with open(filename, 'r') as file:
        text = file.read()
        words = text.split()
        word_counts = Counter(words)
        return word_counts

if __name__ == '__main__':
    if len(sys.argv) != 2:
        print('Usage: python word_counter.py <filename>')
        sys.exit(1)

